  describe("Claim - multiple items", () => {
    it.todo("applies deductible separately per damaged item in a single event");
    it.todo("handles two items of the same type in a policy");
  });

  describe("Claim - payout rounding", () => {
    it.todo("rounds payout down in MHPCO favor");
