const MAIN_ITEM_TYPES = ["sword", "amulet", "staff", "potion"];
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

export const processScenario = (scenario: any): any => {
  const results = scenario.steps.map((step: any) => {
    const mainItems = step.items.filter((item: any) => MAIN_ITEM_TYPES.includes(item.type));
    const components = step.items.filter((item: any) => !MAIN_ITEM_TYPES.includes(item.type));

    const mainTotal = mainItems.reduce(
      (sum: number, item: any) => sum + basePremium(item),
      0,
    );

    const componentCounts: Record<string, number> = {};
    for (const item of components) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    }

    let componentTotal = 0;
    for (const [type, count] of Object.entries(componentCounts)) {
      if (count === COMPONENT_BLOCK_SIZE) {
        componentTotal += COMPONENT_BLOCK_PREMIUM;
      } else {
        componentTotal += count * (BASE_PREMIUMS[type] ?? 0);
      }
    }

    const premium = mainTotal + componentTotal + PROCESSING_FEE;
    return { premium };
  });
  return { results };
};

