            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 155 }] });
    });
  });

  describe("Quote - policy-wide modifiers", () => {
    it("adds 10% first insurance surcharge to policy base premium", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 115 }] });
    });
    it.todo("applies 20% loyalty discount for customer with 2+ years");
    it.todo("applies 15% follow-up discount on second quote in scenario");
  });

  describe("Quote - modifier stacking on multi-item policy", () => {
    it.todo("applies cursed surcharge only to the cursed item, not the whole policy");
    it.todo("sums item base premiums then applies policy-wide modifiers");
  });

  describe("Quote - rounding", () => {
    it.todo("rounds premium up in MHPCO favor");
  });

  describe("Quote - integration", () => {
    it.todo("newcomer with cursed sword: 0 years, first contract, cursed steel sword ench 3 = 165G");
    it.todo("long-standing customer second contract: 3 years, 2nd quote, cursed steel sword ench 7 = 160G");
  });

  describe("Claim - standard reimbursement", () => {
    it.todo("reimburses damage minus 100G deductible for a regular item");
    it.todo("reimburses damage to a component minus 100G deductible");
  });

  describe("Claim - special clauses", () => {
    it.todo("reimburses at 50% for items with enchantment >= 8, then deductible");
    it.todo("fully reimburses dragon material items, then deductible");
    it.todo("applies 50% rule when both dragon material and enchantment >= 8");
    it.todo("fully reimburses dragon material with enchantment < 8, then deductible");
  });

  describe("Claim - cap", () => {
    it.todo("caps total payout at 2x insurance sum");
