const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const MAIN_ITEM_TYPES = ["sword", "amulet", "staff", "potion"];
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const isMainItem = (item: any): boolean =>
  MAIN_ITEM_TYPES.includes(item.type);

const premiumForType = (type: string): number =>
  BASE_PREMIUMS[type] ?? 0;

const countByType = (items: any[]): Record<string, number> => {
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }
  return counts;
};

const calculateComponentPremium = (components: any[]): number => {
  const countsByType = countByType(components);
  return Object.entries(countsByType).reduce(
    (total, [type, count]) =>
      total +
      (count === COMPONENT_BLOCK_SIZE
        ? COMPONENT_BLOCK_PREMIUM
        : count * premiumForType(type)),
    0,
  );
};

const calculateItemPremium = (item: any): number => {
  const base = premiumForType(item.type);
  const cursedSurcharge = item.cursed ? base * 0.5 : 0;
  const enchantmentSurcharge = item.enchantment >= 5 ? base * 0.3 : 0;
  return base + cursedSurcharge + enchantmentSurcharge;
};

export const processScenario = (scenario: any): any => {
  let quoteCount = 0;
  const results = scenario.steps.map((step: any) => {
    quoteCount++;
    const mainItems = step.items.filter(isMainItem);
    const components = step.items.filter((item: any) => !isMainItem(item));

    const mainTotal = mainItems.reduce(
      (sum: number, item: any) => sum + calculateItemPremium(item),
      0,
    );

    const componentTotal = calculateComponentPremium(components);

    const policyBasePremium = mainItems.reduce(
      (sum: number, item: any) => sum + premiumForType(item.type),
      0,
    ) + componentTotal;

    const firstInsurance = policyBasePremium * 0.1;
    const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= 2 ? policyBasePremium * 0.2 : 0;
    const followUpDiscount = quoteCount > 1 ? policyBasePremium * 0.15 : 0;

    const premium = mainTotal + componentTotal + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE;
    return { premium };
  });
  return { results };
};

import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote - base premiums", () => {
    it("returns 5G processing fee for an empty item list", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote" as const, items: [] }],
      });
      expect(result).toEqual({ results: [{ premium: 5 }] });
    });
    it("returns base premium plus fee for a single sword (100 + 5 = 105)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 115 }] });
    });
    it("returns base premium plus fee for a single amulet (60 + 5 = 65)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 71 }] });
    });
    it("returns base premium plus fee for a single staff (80 + 5 = 85)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "staff", material: "wood", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 93 }] });
    });
    it("returns base premium plus fee for a single potion (40 + 5 = 45)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "potion", material: "glass", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 49 }] });
    });
  });

  describe("Quote - components", () => {
    it("returns 25G base premium per component (2 runes = 50 + 5 = 55)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune" },
              { type: "rune" },
            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 60 }] });
    });
    it("applies block discount for exactly 3 alike components (3 runes = 60 + 5 = 65)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune" },
              { type: "rune" },
              { type: "rune" },
            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 71 }] });
    });
    it("does not apply block for 4 alike components (4 runes = 100 + 5 = 105)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune" },
              { type: "rune" },
              { type: "rune" },
              { type: "rune" },
            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 115 }] });
    });
    it("does not apply block for 3 components of different types (2 runes + 1 moonstone = 75 + 5 = 80)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune" },
              { type: "rune" },
              { type: "moonstone" },
            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 87.5 }] });
    });
    it("applies separate blocks for 3 runes and 3 moonstones (120 + 5 = 125)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune" },
              { type: "rune" },
              { type: "rune" },
              { type: "moonstone" },
              { type: "moonstone" },
              { type: "moonstone" },
            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 137 }] });
    });
    it("calculates 7 alike components without block (7 runes = 175 + 5 = 180)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: Array.from({ length: 7 }, () => ({ type: "rune" })),
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 197.5 }] });
    });
  });

  describe("Quote - item-specific modifiers", () => {
    it("adds 50% cursed surcharge to the cursed item base premium", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: true },
            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 165 }] });
    });
    it("adds 30% high-enchantment surcharge for enchantment level 5", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 5, cursed: false },
            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 145 }] });
    });
    it("adds both cursed and high-enchantment surcharges when both apply", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 5, cursed: true },
            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 195 }] });
    });
    it("does not add high-enchantment surcharge for enchantment level 4", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 4, cursed: true },
            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 165 }] });
    });
  });

  describe("Quote - policy-wide modifiers", () => {
    it("adds 10% first insurance surcharge to policy base premium", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 115 }] });
    });
    it("applies 20% loyalty discount for customer with 2+ years", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 2 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 95 }] });
    });
    it("applies 15% follow-up discount on second quote in scenario", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result).toEqual({
        results: [
          { premium: 115 },
          { premium: 100 },
        ],
      });
    });
  });

  describe("Quote - modifier stacking on multi-item policy", () => {
    it.todo("applies cursed surcharge only to the cursed item, not the whole policy");
    it.todo("sums item base premiums then applies policy-wide modifiers");
  });

  describe("Quote - rounding", () => {
    it.todo("rounds premium up in MHPCO favor");
  });

  describe("Quote - integration", () => {
    it.todo("newcomer with cursed sword: 0 years, first contract, cursed steel sword ench 3 = 165G");
    it.todo("long-standing customer second contract: 3 years, 2nd quote, cursed steel sword ench 7 = 160G");
  });

  describe("Claim - standard reimbursement", () => {
    it.todo("reimburses damage minus 100G deductible for a regular item");
    it.todo("reimburses damage to a component minus 100G deductible");
  });

  describe("Claim - special clauses", () => {
    it.todo("reimburses at 50% for items with enchantment >= 8, then deductible");
    it.todo("fully reimburses dragon material items, then deductible");
    it.todo("applies 50% rule when both dragon material and enchantment >= 8");
    it.todo("fully reimburses dragon material with enchantment < 8, then deductible");
  });

  describe("Claim - cap", () => {
    it.todo("caps total payout at 2x insurance sum");
    it.todo("tracks remaining cap across multiple claims on the same policy");
  });

  describe("Claim - multiple items", () => {
    it.todo("applies deductible separately per damaged item in a single event");
    it.todo("handles two items of the same type in a policy");
  });

  describe("Claim - payout rounding", () => {
    it.todo("rounds payout down in MHPCO favor");
  });

  describe("Validation", () => {
    it.todo("rejects unknown item type in quote with error");
    it.todo("rejects claim referencing item not in policy with error");
    it.todo("rejects claim with more damage entries than policy covers for a type");
    it.todo("rejects claim with negative damage amount");
  });
});

